/**
 * Configuration options for the AESP instance
 */
export interface AESPConfig {
    /**
     * The version number of your product. Must be a string consisting of digits and dots,
     * starting with a digit (e.g., "1.0.0"). "beta", "alpha" is not allowed
     */
    productVersion: string;

    // UI Customization Parameters
    /**
     * Full or relative path to an image to display in the About tab of the dialog.
     * For example "/assets/image-sm.png"
     */
    aboutImage?: string;

    /**
     * Custom text content for the About tab, supports basic markdown formatting
     * like: links, bold, italic, list.
     */
    aboutText?: string;

    /**
     * When set to true, disables the blue status bar notifications at the top of the panel
     * and the flyout menu notification. Defaults to false
     */
    statusBarDisabled?: boolean;

    /**
     * When set to true, disables automatic update checking on startup.
     * Defaults to false (updates enabled)
     */
    disableUpdateCheck?: boolean;

    // Beta Mode Parameters
    /**
     * Set to true to enable beta mode. Beta versions accept beta licenses and don't have trials.
     * Defaults to false
     */
    betaMode?: boolean;

    /**
     * JavaScript Date object specifying when the beta expires.
     * Only used when betaMode is true
     */
    betaExpirationDate?: Date;

    // Analytics Parameters
    /**
     * Google Analytics V4 measurement ID (format: "G-XXXXXXX") for custom analytics tracking
     */
    googleAnalyticsMeasurementId?: string;

    /**
     * API secret for the Google Analytics measurement ID.
     * Required if googleAnalyticsMeasurementId is provided
     */
    googleAnalyticsApiSecret?: string;

    /**
     * Analytics configuration for privacy report generation.
     * This replaces the need for an external analytics.json file.
     * The structure follows the same format as the previous analytics.json
     */
    analyticsConfig?: {
        /** Groups of analytics events organized by feature or category */
        Groups: Array<{
            /** Name of the analytics group */
            name: string;
            /** Description of what this group tracks */
            description: string;
            /** Reason why this data is collected */
            reason: string;
            /** Array of events in this group */
            events?: Array<{
                /** Unique identifier for the event */
                id: string;
                /** When this event is sent */
                isSent: string;
                /** Event name sent to analytics */
                name: string;
                /** Parameters sent with the event (key-value pairs with {placeholder} syntax) */
                params?: Record<string, string>;
            }>;
        }>;
    };

    // Flyout Menu Parameters
    /**
     * Callback function that gets called when "Preferences…" is clicked in the flyout menu.
     * If provided, adds a Preferences menu item
     */
    preferencesCallback?: () => void;

    /**
     * Callback function that gets called when "Help…" is clicked in the flyout menu.
     * If provided, adds a Help menu item
     */
    helpCallback?: () => void;

    /**
     * Object with xml (string) and callback (function) properties for custom menu entries
     */
    customFlyoutMenuEntries?: {
        /** XML string defining custom menu entries */
        xml: string;
        /** Function called when custom menu items are clicked */
        callback: (event: { data: { menuId: string } }) => void;
    };
}

/**
 * License types that can be detected by the framework
 */
export type LicenseType =
    | "SUL"  // Single User License
    | "BTA"  // Beta license or beta mode
    | "EDU"  // Educational license
    | "FLT"  // Floating license
    | "SUB"  // Subscription license
    | "ESB"  // Educational Subscription license
    | "ERO"  // Educational render-only license
    | "FSB"  // Floating subscription license
    | "RSB"  // Render-only subscription license
    | "REN"  // Render-only license
    | "none" // No license system
    | string; // Allow other vendor-specific license types

/**
 * Callback function that receives license check results
 */
export type LicenseCheckCallback = (
    /** Whether the license is valid (valid license OR trial period is still active) */
    isValidLicense: boolean,
    /** Whether the software is running in trial mode */
    isTrial: boolean,
    /** Type of license detected */
    licenseType: LicenseType,
    /** Additional license details from the license validation binary */
    details?: any
) => void;

/**
 * Analytics interface for tracking events
 */
export interface Analytics {
    /**
     * Send a custom analytics event to Google Analytics
     * @param name - Event name (e.g., "button_click", "feature_used")
     * @param params - Event parameters as key-value pairs
     */
    sendEvent(name: string, params: Record<string, any>): void;

    /**
     * Set whether analytics tracking is enabled for the user
     * @param value - true to enable analytics, false to disable
     */
    enable(value: boolean): void;

    /**
     * Get the current analytics enabled state
     * @returns true if analytics is enabled, false otherwise
     */
    isEnabled(): boolean;

    /**
     * Analytics report object (if analyticsConfig was provided)
     * Contains methods for interacting with the analytics report
     */
    report?: {
        /** Send an event based on the configured analytics events */
        event(id: string, replacements?: Record<string, string>): void;
        /** Get the analytics JSON configuration */
        getJson(): any;
        /** Check if analytics is enabled */
        isEnabled(): boolean;
    };
}

/**
 * Preferences storage interface for storing user settings
 */
export interface PrefsStorage {
    /** Get a stored value */
    getItem(key: string): any;

    /** Store a value */
    setItem(key: string, value: any): void;

    /** Check if key exists */
    hasItem(key: string): boolean;

    /** Remove a stored value */
    removeItem(key: string): void;
}

/**
 * Logging interface with support for different output targets
 */
export interface Logger {
    (message: string | Error, options?: { support?: boolean; console?: boolean }): void;
}

/**
 * Main AESP instance interface
 */
export interface AESPInstance {
    /** Analytics functionality */
    analytics: Analytics;

    /** Preferences storage system for storing user settings */
    prefsStorage: PrefsStorage;

    /**
     * Dynamically update the panel's flyout menu
     * @param xml - XML string defining the menu structure
     */
    setPanelFlyoutMenu(xml: string): void;

    /**
     * Update the state of a specific menu item
     * @param menuItemLabel - Label of the menu item to update
     * @param enabled - Whether the item should be enabled
     * @param checked - Whether the item should be checked
     */
    updatePanelMenuItem(menuItemLabel: string, enabled: boolean, checked: boolean): void;

    /**
     * Open the licensing dialog on a specific page
     * @param page - The page to open ('license', 'support', 'update', 'about')
     * @param subpage - Sub-page for "support" tab ('customer-care', 'bug-report', 'inspiration-submission')
     * @param licenseCode - License code to set for "license" tab
     */
    openDialogOnPage(page: 'license' | 'support' | 'update' | 'about', subpage?: 'customer-care' | 'bug-report' | 'inspiration-submission', licenseCode?: string): void;

    /**
     * Display a custom notification in the status bar
     * @param message - The notification text to display
     * @param options - Configuration options for the notification
     */
    notify(message: string, options?: {
        /** Unique identifier for the notification */
        id?: string;
        /** Auto-close duration in seconds */
        duration?: number;
        /** Array of buttons to display in the notification */
        buttons?: Array<{
            /** Button label text */
            displayName: string;
            /** Button click handler. Return true to close notification, false to keep open */
            callback: (event: any) => boolean;
        }>;
    }): void;

    /** Framework version string */
    version: string;
}

/**
 * AESP Constructor interface
 */
export interface AESPConstructor {
    new(config: AESPConfig, licenseCheckCallback?: LicenseCheckCallback | null): AESPInstance;
}

/**
 * Main AESP export
 */
declare const AESP: AESPConstructor;

export default AESP;